/// <summary>sizeof = 50</summary>
public class USEITEM_MINIMON_INFO
{
    public byte bNormalItem;
    public byte bChargedItem;
    public ushort[] NormalItemList = new ushort[12];
    public ushort[] ChargedItemList = new ushort[12];

    public void Read(BinaryReader reader)
    {
        bNormalItem = reader.ReadByte();
        bChargedItem = reader.ReadByte();
        for (int i = 0; i < 12; i++)
            NormalItemList[i] = reader.ReadUInt16();
        for (int i = 0; i < 12; i++)
            ChargedItemList[i] = reader.ReadUInt16();
    }

    public void Write(BinaryWriter writer)
    {
        writer.Write(bNormalItem);
        writer.Write(bChargedItem);
        for (int i = 0; i < 12; i++)
            writer.Write(NormalItemList[i]);
        for (int i = 0; i < 12; i++)
            writer.Write(ChargedItemList[i]);
    }

    public void Read(Stream stream) => Read(new BinaryReader(stream, System.Text.Encoding.UTF8, true));
    public void Write(Stream stream) => Write(new BinaryWriter(stream, System.Text.Encoding.UTF8, true));
}

